  return total;
}

function totalQuantity(order: Order): number {
  let total = 0;
  for (const item of order.items) {
    total += item.quantity;
  }
  return total;
}

function distinctLineNames(order: Order): number {
  return new Set(order.items.map((item) => item.name)).size;
}

/** Application order matters: bulk, then multi-line, then loyalty. */
function applyDiscounts(order: Order, amount: number): number {
  if (totalQuantity(order) >= 10) {
    amount *= 0.9;
  }
  if (distinctLineNames(order) >= 3) {
    amount *= 0.98;
  }
  if (order.loyaltyMember) {
    amount *= 0.95;
  }
  return amount;
}

function round(amount: number, currency: Currency): number {
  if (!SUPPORTED_CURRENCIES.includes(currency)) {
    throw new Error(`no rounding policy for currency: ${currency}`);
  }
  return Math.round(amount * 100) / 100;
}

interface Stage {
  name: string;
  run(order: Order, amount: number, vatRate: number): number;
}

const STAGES: Stage[] = [
  { name: "subtotal", run: (order) => subtotal(order) },
  { name: "discount", run: (order, amount) => applyDiscounts(order, amount) },
  { name: "tax", run: (_order, amount, vatRate) => amount * (1 + vatRate) },
  { name: "rounding", run: (order, amount) => round(amount, order.currency) },
];

function runPipeline(
  order: Order,
  vatRate: number,
  hooks: PricingHooks,
): number {
  let amount = 0;
  for (const stage of STAGES) {
    hooks.beforeStage?.(stage.name);
    amount = stage.run(order, amount, vatRate);
    hooks.afterStage?.(stage.name, amount);
  }
  return amount;
}

export class PricingFacade {
  private readonly vatRate: number;
  private readonly hooks: PricingHooks;

  constructor(options?: PricingOptions) {
    this.vatRate = options?.vatRate ?? DEFAULT_VAT_RATE;
    this.hooks = options?.hooks ?? {};
  }

  price(order: Order): number {
    return runPipeline(order, this.vatRate, this.hooks);
  }
}

export function computePrice(order: Order, options?: PricingOptions): number {
  return new PricingFacade(options).price(order);
}
